angular.module("starter").config(function($stateProvider){$stateProvider.state('inapplink-view',{cache:!1,url:BASE_PATH+"/inapplink/mobile_list/index/value_id/:value_id",controller:'InAppLinkController',templateUrl:"modules/inapplink/templates/l1/view.html",})}).controller('InAppLinkController',function($scope,$timeout,$ionicHistory,$location,$timeout,$http,$state,$stateParams,$translate,Url,Dialog){console.log($state);console.log($stateParams);$scope.init=function(){$scope.value_id=$stateParams.value_id;$scope.getSettings()}
$scope.getSettings=function(){$http({method:'GET',url:Url.get("inapplink/mobile_list/findall",{value_id:this.value_id}),cache:!1,responseType:'json'}).then(function(data){$scope.feature=data.data.feature;if($scope.feature){var feature_state=$scope.feature.split('~')[0];var feature_value_id=$scope.feature.split('~')[1];$state.go(feature_state,{value_id:feature_value_id.split(':')[1]},{reload:!0});$timeout(function(){$ionicHistory.removeBackView()},500)}})}
$scope.init();$scope.delete=function(){if($scope.passcode.length>0){$scope.passcode=$scope.passcode.substring(0,$scope.passcode.length-1)}}});Features.insertCSS("","inapplink")